      "status": "pending",
      "task": "Create Express server with Socket.io integration",
      "tool_hint": "project_filesystem for writing server file; powershell_execute for starting server",
      "verification": "Navigate to http://localhost:3000 and see the frontend load"
    },
    {
      "depends_on": [
        "s1"
      ],
      "done_when": "Module exports functions that return current CPU usage percentage and memory usage percentage/bytes",
      "id": "s3",
      "output": "metrics.js module using systeminformation to fetch CPU load and memory usage",
