{"action":"write","content":"const express = require('express');
const { createServer } = require('http');
const { Server } = require('socket.io');
const path = require('path');
const { getMetrics } = require('./metrics');

const app = express();
const httpServer = createServer(app);
const io = new Server(httpServer, {
  cors: {
    origin: '*'
  }
});

const PORT = process.env.PORT || 3000;
const UPDATE_INTERVAL = 1000; // 1 second

// Serve static files from the public directory
app.use(express.static(path.join(__dirname, 'public')));

// Store connected clients count
let connectedClients = 0;

// Metrics broadcast interval
let metricsInterval = null;

/**
 * Start broadcasting metrics to all connected clients
 */
function startMetricsBroadcast() {
  if (metricsInterval) return; // Already running

  console.log('Starting metrics broadcast...');
  metricsInterval = setInterval(async () => {
    try {
      const metrics = await getMetrics();
      io.emit('metrics', metrics);
    } catch (error) {
      console.error('Error broadcasting metrics:', error);
    }
  }, UPDATE_INTERVAL);
}

/**
 * Stop broadcasting metrics
 */
function stopMetricsBroadcast() {
  if (metricsInterval) {
    clearInterval(metricsInterval);
    metricsInterval = null;
    console.log('Stopped metrics broadcast.');
  }
}

// Socket.io connection handling
io.on('connection', (socket) => {
  connectedClients++;
  console.log(`Client connected. Total clients: ${connectedClients}`);

  // Send initial metrics immediately on connection
  getMetrics().then(metrics => {
    socket.emit('metrics', metrics);
  }).catch(err => {
    console.error('Error sending initial metrics:', err);
  });

  // Start broadcasting if this is the first client
  if (connectedClients === 1) {
    startMetricsBroadcast();
  }

  socket.on('disconnect', () => {
    connectedClients--;
    console.log(`Client disconnected. Total clients: ${connectedClients}`);

    // Stop broadcasting if no clients are connected
    if (connectedClients === 0) {
      stopMetricsBroadcast();
    }
  });
});

// Start the server
httpServer.listen(PORT, () => {
  console.log(`Server running on http://localhost:${PORT}`);
  console.log(`Press Ctrl+C to stop the server`);
});

// Graceful shutdown
process.on('SIGINT', () => {
  console.log('\nShutting down server...');
  stopMetricsBroadcast();
  io.close(() => {
    httpServer.close(() => {
      console.log('Server closed.');
      process.exit(0);
    });
  });
});
","path":"server.js"}

