{"command":"cd "$env:ProjectFolder" ; node -e "
const m = require('./metrics');
let count = 0;
const interval = setInterval(async () => {
  const d = await m.getMetrics();
  console.log('[' + (++count) + '] CPU: ' + d.cpu.toFixed(1) + '% | Memory: ' + d.memory.usedPercent.toFixed(1) + '%');
  if (count >= 5) clearInterval(interval);
}, 1000);
"","timeout_seconds":15}

