  grid-template-columns: 1fr;
  gap: 25px;
  margin-bottom: 30px;
}

/* Metric Card */
.metric-card {
  background: rgba(255, 255, 255, 0.05);
  border-radius: 16px;
  padding: 25px;
  border: 1px solid rgba(255, 255, 255, 0.1);
  backdrop-filter: blur(10px);
  transition: transform 0.2s ease, box-shadow 0.2s ease;
}

.metric-card:hover {
  transform: translateY(-2px);
  box-shadow: 0 8px 32px rgba(0, 0, 0, 0.3);
}

.metric-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 15px;
}

.metric-header h2 {
  font-size: 1.3rem;
  font-weight: 500;
  color: #fff;
}

.metric-value {
  display: flex;
  align-items: baseline;
  gap: 4px;
}

.metric-value .value {
  font-size: 2rem;
  font-weight: 700;
  color: #fff;
}

.metric-value .unit {
  font-size: 1rem;
  color: #888;
}

/* Memory Details */
.memory-details {
  font-size: 0.9rem;
  color: #888;
  margin-bottom: 15px;
  text-align: right;
}

/* Disk Details */
.disk-details {
  font-size: 0.9rem;
  color: #888;
  margin-bottom: 15px;
  text-align: right;
}

/* Chart Container */
.chart-container {
  position: relative;
  height: 300px;
  width: 100%;
}

/* Footer */
footer {
  text-align: center;
  padding-top: 20px;
  border-top: 1px solid rgba(255, 255, 255, 0.1);
  color: #666;
  font-size: 0.85rem;
}

/* Responsive Design */
@media (min-width: 768px) {
  .metrics-grid {
    grid-template-columns: 1fr 1fr;
  }

  h1 {
    font-size: 2.5rem;
  }

  .metric-header h2 {
    font-size: 1.5rem;
  }

  .metric-value .value {
    font-size: 2.5rem;
  }
}

@media (min-width: 1200px) {
  .metrics-grid {
    grid-template-columns: 1fr 1fr 1fr;
  }

  .container {
    padding: 40px;
  }

  .chart-container {
    height: 280px;
  }
}

/* Scrollbar styling */
::-webkit-scrollbar {
  width: 8px;
}

::-webkit-scrollbar-track {
  background: #1a1a2e;
}

::-webkit-scrollbar-thumb {
  background: #444;
  border-radius: 4px;
}

::-webkit-scrollbar-thumb:hover {
  background: #555;
}
