Read file: public/styles.css

/* Reset and base styles */
* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

body {
  font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, Oxygen, Ubuntu, sans-serif;
  background: linear-gradient(135deg, #1a1a2e 0%, #16213e 100%);
  color: #e0e0e0;
  min-height: 100vh;
  line-height: 1.6;
}

.container {
  max-width: 1400px;
  margin: 0 auto;
  padding: 20px;
}

/* Header */
header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 30px;
  padding-bottom: 20px;
  border-bottom: 1px solid rgba(255, 255, 255, 0.1);
}

h1 {
  font-size: 2rem;
  font-weight: 600;
  color: #fff;
  letter-spacing: -0.5px;
}

/* Status Indicator */
.status-indicator {
  display: flex;
  align-items: center;
  gap: 8px;
  font-size: 0.9rem;
}

.status-dot {
  width: 10px;
  height: 10px;
  border-radius: 50%;
  background-color: #ffc107;
  transition: background-color 0.3s ease;
  animation: pulse 2s infinite;
}

.status-dot.connected {
  background-color: #28a745;
  animation: none;
}

.status-dot.disconnected {
  background-color: #dc3545;
  animation: none;
}

@keyframes pulse {
  0% { opacity: 1; }
  50% { opacity: 0.5; }
  100% { opacity: 1; }
}

/* Metrics Grid */
.metrics-grid {
  display: grid;
  grid-template-columns: 1fr;
  gap: 25px;
  margin-bottom: 30px;
}

/* Metric Card */
.metric-card {
  background: rgba(255, 255, 255, 0.05);
  border-radius: 16px;
  padding: 25px;
  border: 1px solid rgba(255, 255, 255, 0.1);
  backdrop-filter: blur(10px);
  transition: transform 0.2s ease, box-shadow 0.2s ease, border-color 0.3s ease;
}

.metric-card:hover {
  transform: translateY(-2px);
  box-shadow: 0 8px 32px rgba(0, 0, 0, 0.3);
}

/* Alert States for Metric Cards */
.metric-card.alert-low {
  border-color: rgba(40, 167, 69, 0.4);
  box-shadow: 0 0 20px rgba(40, 167, 69, 0.1);
}

.metric-card.alert-medium {
  border-color: rgba(255, 193, 7, 0.5);
  box-shadow: 0 0 20px rgba(255, 193, 7, 0.15);
}

.metric-card.alert-high {
  border-color: rgba(220, 53, 69, 0.6);
  box-shadow: 0 0 25px rgba(220, 53, 69, 0.2);
  animation: alertPulse 2s infinite;
}

@keyframes alertPulse {
  0% { box-shadow: 0 0 25px rgba(220, 53, 69, 0.2); }
  50% { box-shadow: 0 0 35px rgba(220, 53, 69, 0.35); }
  100% { box-shadow: 0 0 25px rgba(220, 53, 69, 0.2); }
}

.metric-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 15px;
}

.metric-header h2 {
  font-size: 1.3rem;
  font-weight: 500;
  color: #fff;
}

.metric-value {
  display: flex;
  align-items: baseline;
  gap: 4px;
}

.metric-value .value {
  font-size: 2rem;
  font-weight: 700;
  color: #fff;
  transition: color 0.3s ease;
}

.metric-value .value.alert-low {
  color: #28a745;
}

.metric-value .value.alert-medium {
  color: #ffc107;
}

.metric-value .value.alert-high {
  color: #dc3545;
}

.metric-value .unit {
  font-size: 1rem;
  color: #888;
}

/* Memory Details */
.memory-details {
  font-size: 0.9rem;
  color: #888;
  margin-bottom: 15px;
  text-align: right;
}

/* Disk Details */
.disk-details {
  font-size: 0.9rem;
  color: #888;
  margin-bottom: 15px;
  text-align: right;
}

/* Chart Container */
.chart-container {
  position: relative;
  height: 300px;
  width: 100%;
}

/* Footer */
footer {
  text-align: center;
  padding-top: 20px;
  border-top: 1px solid rgba(255, 255, 255, 0.1);
  color: #666;
  font-size: 0.85rem;
}

/* Responsive Design */
@media (min-width: 768px) {
  .metrics-grid {
    grid-template-columns: 1fr 1fr;
  }

  h1 {
    font-size: 2.5rem;
  }

  .metric-header h2 {
    font-size: 1.5rem;
  }

  .metric-value .value {
    font-size: 2.5rem;
  }
}

@media (min-width: 1200px) {
  .metrics-grid {
    grid-template-columns: 1fr 1fr 1fr;
  }

  .container {
    padding: 40px;
  }

  .chart-container {
    height: 280px;
  }
}

/* Scrollbar styling */
::-webkit-scrollbar {
  width: 8px;
}

::-webkit-scrollbar-track {
  background: #1a1a2e;
}

::-webkit-scrollbar-thumb {
  background: #444;
  border-radius: 4px;
}

::-webkit-scrollbar-thumb:hover {
  background: #555;
}

/* Processes Section */
.processes-section {
  margin-top: 20px;
  margin-bottom: 30px;
}

.section-title {
  font-size: 1.5rem;
  font-weight: 600;
  color: #fff;
  margin-bottom: 20px;
  padding-bottom: 10px;
  border-bottom: 1px solid rgba(255, 255, 255, 0.1);
}

.processes-grid {
  display: grid;
  grid-template-columns: 1fr;
  gap: 25px;
}

.process-card {
  background: rgba(255, 255, 255, 0.05);
  border-radius: 16px;
  padding: 25px;
  border: 1px solid rgba(255, 255, 255, 0.1);
  backdrop-filter: blur(10px);
}

.process-card h3 {
  font-size: 1.1rem;
  font-weight: 500;
  color: #fff;
  margin-bottom: 15px;
}

.process-table {
  width: 100%;
  border-collapse: collapse;
  font-size: 0.9rem;
}

.process-table thead {
  background: rgba(255, 255, 255, 0.05);
}

.process-table th {
  padding: 12px 15px;
  text-align: left;
  font-weight: 600;
  color: #aaa;
  border-bottom: 1px solid rgba(255, 255, 255, 0.1);
}

.process-table td {
  padding: 10px 15px;
  border-bottom: 1px solid rgba(255, 255, 255, 0.05);
  color: #ccc;
}

.process-table tbody tr:hover {
  background: rgba(255, 255, 255, 0.03);
}

.process-table tbody tr:last-child td {
  border-bottom: none;
}

.process-table .loading {
  text-align: center;
  color: #666;
  font-style: italic;
}

.process-table td:nth-child(3),
.process-table td:nth-child(4) {
  text-align: right;
}

.process-table th:nth-child(3),
.process-table th:nth-child(4) {
  text-align: right;
}

/* Responsive Design for Processes */
@media (min-width: 768px) {
  .processes-grid {
    grid-template-columns: 1fr 1fr;
  }
}

