/**
 * System Monitor Frontend
 * Handles real-time chart updates via Socket.io
 */

// Configuration
const MAX_DATA_POINTS = 60; // Keep last 60 seconds of data
const UPDATE_INTERVAL = 1000; // 1 second

// Alert Thresholds
const ALERT_LOW = 50;      // Green: below 50%
const ALERT_MEDIUM = 80;   // Yellow: 50-80%
// Red: above 80%

// DOM Elements
const statusDot = document.getElementById('statusDot');
const statusText = document.getElementById('statusText');
const cpuValue = document.getElementById('cpuValue');
const memoryValue = document.getElementById('memoryValue');
const memoryUsed = document.getElementById('memoryUsed');
const memoryTotal = document.getElementById('memoryTotal');
const diskValue = document.getElementById('diskValue');
const diskUsed = document.getElementById('diskUsed');
const diskTotal = document.getElementById('diskTotal');

// Process table elements
const cpuProcessTable = document.getElementById('cpuProcessTable').querySelector('tbody');
const memoryProcessTable = document.getElementById('memoryProcessTable').querySelector('tbody');

// Card elements for alert styling
const cpuCard = cpuValue.closest('.metric-card');
const memoryCard = memoryValue.closest('.metric-card');
const diskCard = diskValue.closest('.metric-card');

// Chart.js default configuration
Chart.defaults.color = '#888';
Chart.defaults.borderColor = 'rgba(255, 255, 255, 0.1)';
Chart.defaults.font.family = '-apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif';

/**
 * Determine alert level based on usage percentage
 * @param {number} percent - Usage percentage (0-100)
 * @returns {string} 'low', 'medium', or 'high'
 */
function getAlertLevel(percent) {
  if (percent >= ALERT_MEDIUM) return 'high';
  if (percent >= ALERT_LOW) return 'medium';
  return 'low';
}

/**
 * Apply alert styling to a metric card and its value element
 * @param {HTMLElement} card - The metric card element
 * @param {HTMLElement} valueEl - The value span element
 * @param {number} percent - Current usage percentage
 */
function applyAlertState(card, valueEl, percent) {
  const level = getAlertLevel(percent);

  // Remove all alert classes
  card.classList.remove('alert-low', 'alert-medium', 'alert-high');
  valueEl.classList.remove('alert-low', 'alert-medium', 'alert-high');

  // Add appropriate alert class
  card.classList.add('alert-' + level);
  valueEl.classList.add('alert-' + level);
}

/**
 * Create a line chart with the given configuration
 */
function createLineChart(canvasId, label, color, yAxisMax = 100) {
  const ctx = document.getElementById(canvasId).getContext('2d');

  // Create gradient fill
  const gradient = ctx.createLinearGradient(0, 0, 0, 300);
  gradient.addColorStop(0, color.replace('1)', '0.3)'));
  gradient.addColorStop(1, color.replace('1)', '0.0)'));

  return new Chart(ctx, {
    type: 'line',
    data: {
      labels: [],
      datasets: [{
        label: label,
        data: [],
        borderColor: color,
        backgroundColor: gradient,
        borderWidth: 2,
        fill: true,
        tension: 0.4,
        pointRadius: 0,
        pointHoverRadius: 4,
        pointHoverBackgroundColor: color,
        pointHoverBorderColor: '#fff',
        pointHoverBorderWidth: 2
      }]
    },
    options: {
      responsive: true,
      maintainAspectRatio: false,
      animation: {
        duration: 0 // Disable animation for smooth real-time updates
      },
      interaction: {
        intersect: false,
        mode: 'index'
      },
      plugins: {
        legend: {
          display: false
        },
        tooltip: {
          backgroundColor: 'rgba(0, 0, 0, 0.8)',
          titleColor: '#fff',
          bodyColor: '#fff',
          borderColor: 'rgba(255, 255, 255, 0.1)',
          borderWidth: 1,
          padding: 10,
          displayColors: false,
          callbacks: {
            title: function(context) {
              return 'Time: ' + context[0].label;
            },
            label: function(context) {
              return context.dataset.label + ': ' + context.parsed.y.toFixed(1) + '%';
            }
          }
        }
      },
      scales: {
        x: {
          grid: {
            display: false
          },
          ticks: {
            maxTicksLimit: 6,
            maxRotation: 0
          }
        },
        y: {
          min: 0,
          max: yAxisMax,
          grid: {
            color: 'rgba(255, 255, 255, 0.05)'
          },
          ticks: {
            callback: function(value) {
              return value + '%';
            }
          }
        }
      }
    }
  });
}

/**
 * Create a donut chart for disk usage
 */
function createDonutChart(canvasId, label, usedColor, availableColor) {
  const ctx = document.getElementById(canvasId).getContext('2d');

  return new Chart(ctx, {
    type: 'doughnut',
    data: {
      labels: ['Used', 'Available'],
      datasets: [{
        data: [0, 100],
        backgroundColor: [usedColor, availableColor],
        borderColor: 'rgba(255, 255, 255, 0.1)',
        borderWidth: 2,
        hoverOffset: 4
      }]
    },
    options: {
      responsive: true,
      maintainAspectRatio: false,
      cutout: '65%',
      animation: {
        duration: 500
      },
      plugins: {
        legend: {
          display: true,
          position: 'bottom',
          labels: {
            color: '#888',
            padding: 15,
            usePointStyle: true,
            pointStyle: 'circle'
          }
        },
        tooltip: {
          backgroundColor: 'rgba(0, 0, 0, 0.8)',
          titleColor: '#fff',
          bodyColor: '#fff',
          borderColor: 'rgba(255, 255, 255, 0.1)',
          borderWidth: 1,
          padding: 10,
          callbacks: {
            label: function(context) {
              return context.label + ': ' + context.parsed.toFixed(1) + '%';
            }
          }
        }
      }
    }
  });
}

// Initialize charts
const cpuChart = createLineChart('cpuChart', 'CPU Usage', 'rgba(75, 192, 192, 1)');
const memoryChart = createLineChart('memoryChart', 'Memory Usage', 'rgba(255, 99, 132, 1)');
const diskChart = createDonutChart('diskChart', 'Disk Usage', 'rgba(255, 206, 86, 1)', 'rgba(75, 192, 192, 0.3)');

/**
 * Format time for chart labels
 */
function formatTime(timestamp) {
  const date = new Date(timestamp);
  return date.toLocaleTimeString('en-US', { 
    hour12: false, 
    hour: '2-digit', 
    minute: '2-digit', 
    second: '2-digit' 
  });
}

/**
 * Update line chart with new data point
 */
function updateLineChart(chart, label, value) {
  chart.data.labels.push(label);
  chart.data.datasets[0].data.push(value);

  // Remove old data points if exceeding max
  if (chart.data.labels.length > MAX_DATA_POINTS) {
    chart.data.labels.shift();
    chart.data.datasets[0].data.shift();
  }

  chart.update('none'); // Update without animation for performance
}

/**
 * Update donut chart with new data
 */
function updateDonutChart(chart, usedPercent) {
  chart.data.datasets[0].data = [usedPercent, Math.max(0, 100 - usedPercent)];
  chart.update();
}

/**
 * Update connection status UI
 */
function updateStatus(connected) {
  if (connected) {
    statusDot.className = 'status-dot connected';
    statusText.textContent = 'Connected';
    statusText.style.color = '#28a745';
  } else {
    statusDot.className = 'status-dot disconnected';
    statusText.textContent = 'Disconnected';
    statusText.style.color = '#dc3545';
  }
}

/**
 * Render a process table with the given data
 * @param {HTMLElement} tableBody - The tbody element
 * @param {Array} processes - Array of process objects
 */
function renderProcessTable(tableBody, processes) {
  if (!processes || processes.length === 0) {
    tableBody.innerHTML = '<tr><td colspan="4" class="loading">No process data available</td></tr>';
    return;
  }

  tableBody.innerHTML = processes.map(p => `
    <tr>
      <td>${escapeHtml(p.name)}</td>
      <td>${p.pid}</td>
      <td>${p.cpu.toFixed(1)}%</td>
      <td>${p.memoryMB.toLocaleString()} MB</td>
    </tr>
  `).join('');
}

/**
 * Escape HTML to prevent XSS
 * @param {string} text - Raw text
 * @returns {string} Escaped text
 */
function escapeHtml(text) {
  const div = document.createElement('div');
  div.textContent = text;
  return div.innerHTML;
}

/**
 * Update metric values display and alert states
 */
function updateMetricValues(data) {
  // Update CPU
  cpuValue.textContent = data.cpu.toFixed(1);
  applyAlertState(cpuCard, cpuValue, data.cpu);

  // Update Memory
  memoryValue.textContent = data.memory.usedPercent.toFixed(1);
  memoryUsed.textContent = data.memory.usedMB.toLocaleString();
  memoryTotal.textContent = data.memory.totalMB.toLocaleString();
  applyAlertState(memoryCard, memoryValue, data.memory.usedPercent);

  // Update Disk
  if (data.disk) {
    diskValue.textContent = data.disk.usedPercent.toFixed(1);
    diskUsed.textContent = data.disk.totalUsedGB.toLocaleString();
    diskTotal.textContent = data.disk.totalSizeGB.toLocaleString();
    applyAlertState(diskCard, diskValue, data.disk.usedPercent);
  }

  // Update Process Tables
  if (data.processes) {
    renderProcessTable(cpuProcessTable, data.processes.byCpu);
    renderProcessTable(memoryProcessTable, data.processes.byMemory);
  }
}

// Initialize Socket.io connection
const socket = io();

socket.on('connect', () => {
  console.log('Connected to server');
  updateStatus(true);
});

socket.on('disconnect', () => {
  console.log('Disconnected from server');
  updateStatus(false);
});

socket.on('connect_error', (error) => {
  console.error('Connection error:', error);
  updateStatus(false);
});

// Handle incoming metrics data
socket.on('metrics', (data) => {
  console.log('Received metrics:', data);

  const timeLabel = formatTime(data.timestamp);

  // Update line charts
  updateLineChart(cpuChart, timeLabel, data.cpu);
  updateLineChart(memoryChart, timeLabel, data.memory.usedPercent);

  // Update donut chart
  if (data.disk) {
    updateDonutChart(diskChart, data.disk.usedPercent);
  }

  // Update numeric displays and alert states
  updateMetricValues(data);
});

// Handle page visibility changes to pause/resume updates
document.addEventListener('visibilitychange', () => {
  if (document.hidden) {
    console.log('Page hidden - charts will resume when visible');
  } else {
    console.log('Page visible - resuming chart updates');
  }
});

// Handle window resize for responsive charts
window.addEventListener('resize', () => {
  cpuChart.resize();
  memoryChart.resize();
  diskChart.resize();
});

console.log('System Monitor frontend initialized');

