const si = require('systeminformation');

/**
 * Get current CPU usage percentage.
 * Uses systeminformation's currentLoad which returns the average CPU load
 * across all cores since the last call.
 * @returns {Promise<number>} CPU usage percentage (0-100)
 */
async function getCpuUsage() {
  try {
    const load = await si.currentLoad();
    return parseFloat(load.currentLoad.toFixed(1));
  } catch (error) {
    console.error('Error fetching CPU usage:', error);
    return 0;
  }
}

/**
 * Get current memory usage statistics.
 * @returns {Promise<Object>} Memory usage data
 *   - usedPercent: percentage of memory used (0-100)
 *   - usedMB: used memory in megabytes
 *   - totalMB: total memory in megabytes
 *   - freeMB: free memory in megabytes
 */
async function getMemoryUsage() {
  try {
    const mem = await si.mem();
    const totalMB = Math.round(mem.total / 1024 / 1024);
    const usedMB = Math.round(mem.used / 1024 / 1024);
    const freeMB = Math.round(mem.free / 1024 / 1024);
    const usedPercent = parseFloat(((mem.used / mem.total) * 100).toFixed(1));

    return {
      usedPercent,
      usedMB,
      totalMB,
      freeMB
    };
  } catch (error) {
    console.error('Error fetching memory usage:', error);
    return {
      usedPercent: 0,
      usedMB: 0,
      totalMB: 0,
      freeMB: 0
    };
  }
}

/**
 * Get disk usage statistics for all mounted drives.
 * @returns {Promise<Object>} Disk usage data
 *   - drives: array of drive objects with fs, type, size, used, available, usePercent
 *   - totalSizeGB: total size across all drives in GB
 *   - totalUsedGB: total used space in GB
 *   - totalAvailableGB: total available space in GB
 *   - usedPercent: overall percentage used (0-100)
 */
async function getDiskUsage() {
  try {
    const drives = await si.fsSize();

    let totalSize = 0;
    let totalUsed = 0;
    let totalAvailable = 0;

    const driveData = drives.map(drive => {
      const sizeGB = drive.size / 1024 / 1024 / 1024;
      const usedGB = drive.used / 1024 / 1024 / 1024;
      const availableGB = drive.available / 1024 / 1024 / 1024;
      const usePercent = parseFloat(drive.use.toFixed(1));

      totalSize += drive.size;
      totalUsed += drive.used;
      totalAvailable += drive.available;

      return {
        fs: drive.fs,
        type: drive.type,
        sizeGB: parseFloat(sizeGB.toFixed(1)),
        usedGB: parseFloat(usedGB.toFixed(1)),
        availableGB: parseFloat(availableGB.toFixed(1)),
        usePercent
      };
    });

    const usedPercent = parseFloat(((totalUsed / totalSize) * 100).toFixed(1));

    return {
      drives: driveData,
      totalSizeGB: parseFloat((totalSize / 1024 / 1024 / 1024).toFixed(1)),
      totalUsedGB: parseFloat((totalUsed / 1024 / 1024 / 1024).toFixed(1)),
      totalAvailableGB: parseFloat((totalAvailable / 1024 / 1024 / 1024).toFixed(1)),
      usedPercent
    };
  } catch (error) {
    console.error('Error fetching disk usage:', error);
    return {
      drives: [],
      totalSizeGB: 0,
      totalUsedGB: 0,
      totalAvailableGB: 0,
      usedPercent: 0
    };
  }
}

/**
 * Get top processes by CPU and memory usage.
 * @returns {Promise<Object>} Top processes data
 *   - byCpu: array of top 5 processes by CPU usage
 *   - byMemory: array of top 5 processes by memory usage
 */
async function getTopProcesses() {
  try {
    const processes = await si.processes();

    // Sort by CPU usage (descending) and take top 5
    const byCpu = processes.list
      .sort((a, b) => b.cpu - a.cpu)
      .slice(0, 5)
      .map(p => ({
        name: p.name,
        pid: p.pid,
        cpu: parseFloat(p.cpu.toFixed(1)),
        memoryMB: Math.round(p.memRss / 1024)
      }));

    // Sort by memory usage (descending) and take top 5
    const byMemory = processes.list
      .sort((a, b) => b.memRss - a.memRss)
      .slice(0, 5)
      .map(p => ({
        name: p.name,
        pid: p.pid,
        cpu: parseFloat(p.cpu.toFixed(1)),
        memoryMB: Math.round(p.memRss / 1024)
      }));

    return { byCpu, byMemory };
  } catch (error) {
    console.error('Error fetching top processes:', error);
    return { byCpu: [], byMemory: [] };
  }
}

/**
 * Get CPU, memory, disk, and top processes metrics in one call.
 * @returns {Promise<Object>} Combined metrics object with timestamp
 */
async function getMetrics() {
  const [cpu, memory, disk, processes] = await Promise.all([
    getCpuUsage(),
    getMemoryUsage(),
    getDiskUsage(),
    getTopProcesses()
  ]);

  return {
    timestamp: new Date().toISOString(),
    cpu,
    memory,
    disk,
    processes
  };
}

module.exports = {
  getCpuUsage,
  getMemoryUsage,
  getDiskUsage,
  getTopProcesses,
  getMetrics
};

