/**
 * Determine alert level based on usage percentage
 * @param {number} percent - Usage percentage (0-100)
 * @returns {string} 'low', 'medium', or 'high'
 */
function getAlertLevel(percent) {
  if (percent >= ALERT_MEDIUM) return 'high';
  if (percent >= ALERT_LOW) return 'medium';
  return 'low';
}

/**
 * Apply alert styling to a metric card and its value element
 * @param {HTMLElement} card - The metric card element
 * @param {HTMLElement} valueEl - The value span element
 * @param {number} percent - Current usage percentage
 */
function applyAlertState(card, valueEl, percent) {
  const level = getAlertLevel(percent);

  // Remove all alert classes
  card.classList.remove('alert-low', 'alert-medium', 'alert-high');
  valueEl.classList.remove('alert-low', 'alert-medium', 'alert-high');

  // Add appropriate alert class
  card.classList.add('alert-' + level);
  valueEl.classList.add('alert-' + level);
}

